<?php
// Generated by Cursor prompt — module: Envanter (AssetController) — date: 2026-03-15

namespace App\Modules\Envanter\Controllers;

use App\Http\Controllers\Controller;
use App\Modules\Envanter\Models\Asset;
use App\Modules\Envanter\Models\AssetType;
use App\Modules\Envanter\Models\AssetAssignment;
use App\Modules\Envanter\Requests\StoreAssetRequest;
use Illuminate\Http\Request;
use Illuminate\Http\JsonResponse;
use Illuminate\Support\Facades\DB;

class AssetController extends Controller
{
    /** Varlık listesi — Ajax DataTable JSON */
    public function index(Request $request): JsonResponse
    {
        $this->authorize('asset.view');
        $companyId = auth()->user()->company_id;

        $query = Asset::with(['assetType', 'assignedPersonel'])
            ->forCompany($companyId);

        if ($request->filled('search')) {
            $s = $request->search;
            $query->where(fn ($q) => $q->where('name', 'like', "%{$s}%")
                ->orWhere('serial', 'like', "%{$s}%")
                ->orWhere('barcode', 'like', "%{$s}%"));
        }

        if ($request->filled('asset_type_id')) {
            $query->where('asset_type_id', $request->asset_type_id);
        }

        if ($request->filled('status')) {
            $query->where('status', $request->status);
        }

        if ($request->filled('personel_id')) {
            $query->where('assigned_to', $request->personel_id);
        }

        $assets = $query
            ->orderBy($request->get('sort_by', 'name'), $request->get('sort_dir', 'asc'))
            ->paginate($request->get('per_page', 20));

        return response()->json([
            'data'  => $assets->map(fn ($a) => array_merge($a->toArray(), [
                'status_label'           => $a->status_label,
                'status_color'           => $a->status_color,
                'warranty_status_color'  => $a->warranty_status_color,
                'is_warranty_expired'    => $a->isWarrantyExpired(),
            ])),
            'total' => $assets->total(),
            'pages' => $assets->lastPage(),
        ]);
    }

    /** Envanter sayfası view */
    public function indexView()
    {
        $this->authorize('asset.view');
        $companyId  = auth()->user()->company_id;
        $assetTypes = AssetType::forCompany($companyId)->active()->get();
        $personels  = \App\Modules\Personel\Models\Personel::forCompany($companyId)->active()
            ->select('id', 'first_name', 'last_name')->get();
        return view('admin.assets.index', compact('assetTypes', 'personels'));
    }

    /** Create form */
    public function create(): JsonResponse
    {
        $this->authorize('asset.create');
        $companyId  = auth()->user()->company_id;
        $assetTypes = AssetType::forCompany($companyId)->active()->get();
        return response()->json(['html' => view('admin.assets._form', compact('assetTypes'))->render()]);
    }

    /** Yeni varlık kaydet */
    public function store(StoreAssetRequest $request): JsonResponse
    {
        $this->authorize('asset.create');

        $data               = $request->validated();
        $data['company_id'] = auth()->user()->company_id;
        $data['status']     = $data['status'] ?? Asset::STATUS_AVAILABLE;

        $asset = Asset::create($data);

        $this->auditLog('asset.created', $asset);

        return response()->json([
            'success' => true,
            'message' => 'Varlık oluşturuldu.',
            'data'    => array_merge($asset->load('assetType')->toArray(), [
                'status_label' => $asset->status_label,
            ]),
        ], 201);
    }

    /** Edit form */
    public function edit(Asset $asset): JsonResponse
    {
        $this->authorize('asset.update');
        $companyId  = auth()->user()->company_id;
        $assetTypes = AssetType::forCompany($companyId)->active()->get();
        return response()->json(['html' => view('admin.assets._form', compact('asset', 'assetTypes'))->render()]);
    }

    /** Güncelle */
    public function update(StoreAssetRequest $request, Asset $asset): JsonResponse
    {
        $this->authorize('asset.update');

        $asset->update($request->validated());
        $this->auditLog('asset.updated', $asset);

        return response()->json([
            'success' => true,
            'message' => 'Varlık güncellendi.',
            'data'    => array_merge($asset->fresh(['assetType'])->toArray(), ['status_label' => $asset->status_label]),
        ]);
    }

    /** Sil */
    public function destroy(Asset $asset): JsonResponse
    {
        $this->authorize('asset.delete');

        if ($asset->status === Asset::STATUS_ASSIGNED) {
            return response()->json([
                'success' => false,
                'message' => 'Zimmetli varlık silinemez. Önce iade alınız.',
            ], 422);
        }

        $asset->delete();
        $this->auditLog('asset.deleted', $asset);

        return response()->json(['success' => true, 'message' => 'Varlık silindi.']);
    }

    // ─── Zimmet İşlemleri ─────────────────────────────────────────────────────

    /** Personele zimmetle */
    public function assign(Request $request, Asset $asset): JsonResponse
    {
        $this->authorize('asset.assign');

        $request->validate([
            'personel_id' => 'required|exists:personels,id',
            'condition'   => 'nullable|string|max:191',
            'notes'       => 'nullable|string|max:500',
        ]);

        try {
            $assignment = $asset->assignTo(
                $request->personel_id,
                $request->condition,
                $request->notes
            );

            $this->auditLog('asset.assigned', $asset);

            return response()->json([
                'success'    => true,
                'message'    => 'Varlık zimmetlendi.',
                'assignment' => $assignment->load('personel'),
            ]);

        } catch (\LogicException $e) {
            return response()->json(['success' => false, 'message' => $e->getMessage()], 422);
        }
    }

    /** Zimmetinden geri al */
    public function return(Request $request, Asset $asset): JsonResponse
    {
        $this->authorize('asset.assign');

        $request->validate([
            'condition' => 'nullable|string|max:191',
            'notes'     => 'nullable|string|max:500',
        ]);

        $result = $asset->returnAsset($request->condition, $request->notes);

        if (!$result) {
            return response()->json(['success' => false, 'message' => 'Aktif zimmet bulunamadı.'], 422);
        }

        $this->auditLog('asset.returned', $asset);

        return response()->json(['success' => true, 'message' => 'Varlık iade alındı.']);
    }

    /** Zimmet geçmişi */
    public function history(Asset $asset): JsonResponse
    {
        $this->authorize('asset.view');

        $history = $asset->assignments()->with('personel', 'assignedBy')
            ->orderByDesc('assigned_at')
            ->get();

        return response()->json(['data' => $history]);
    }

    /** Zimmet sözleşmesi PDF (stub — gerçek implementasyon ayrı prompt'la) */
    public function zimmetPdf(AssetAssignment $assetAssignment): JsonResponse
    {
        $this->authorize('asset.assign');
        // TODO: PDF oluşturma job'ı dispatch edilecek
        return response()->json(['success' => true, 'message' => 'Zimmet belgesi hazırlanıyor...']);
    }

    /** Excel export — arka plan job */
    public function exportExcel(Request $request): JsonResponse
    {
        $this->authorize('asset.view');
        $companyId = auth()->user()->company_id;

        \App\Jobs\ExportPersonelExcelJob::dispatch(
            $companyId,
            auth()->id(),
            array_merge($request->only(['asset_type_id', 'status']), ['module' => 'assets'])
        );

        return response()->json([
            'success' => true,
            'message' => 'Envanter dışa aktarma başlatıldı. Tamamlandığında bildirim alacaksınız.',
        ]);
    }

    /** Varlık türleri CRUD */
    public function types(Request $request): JsonResponse
    {
        $this->authorize('asset.manage');
        $companyId = auth()->user()->company_id;
        $types = AssetType::forCompany($companyId)->withCount('assets')->get();
        return response()->json(['data' => $types]);
    }

    public function storeType(Request $request): JsonResponse
    {
        $this->authorize('asset.manage');

        $data = $request->validate([
            'name'               => 'required|string|max:191',
            'attributes_schema'  => 'nullable|array',
            'is_active'          => 'nullable|boolean',
        ]);

        $data['company_id'] = auth()->user()->company_id;
        $type = AssetType::create($data);

        return response()->json(['success' => true, 'message' => 'Varlık türü oluşturuldu.', 'data' => $type], 201);
    }

    private function auditLog(string $action, Asset $asset): void
    {
        DB::table('audit_logs')->insert([
            'user_id'    => auth()->id(),
            'company_id' => $asset->company_id,
            'action'     => $action,
            'model_type' => Asset::class,
            'model_id'   => $asset->id,
            'ip'         => request()->ip(),
            'created_at' => now(),
        ]);
    }
}
